import { describe, expect, it } from "vitest";
import { createLimiter } from "../src/limiter.js";

// Exhaustive behavioral test suite for the sliding-window rate limiter.
//
// The documented contract (see src/limiter.js) is:
//   createLimiter(limit = 5, windowMs = 60000) -> { allow(key, now) }
//   - allow(key, now) returns true and RECORDS the call iff the number of
//     previously allowed calls for `key` with timestamp t satisfying
//     t > now - windowMs is strictly less than `limit`; else returns false
//     and records nothing.
//   - a call exactly windowMs old (t === now - windowMs) has expired.
//   - keys are independent buckets.
//   - throws TypeError if `now` is not a finite number.
//
// Each test below is designed to fail if any one of those clauses is broken.

describe("createLimiter — shape", () => {
  it("returns an object exposing an allow function", () => {
    const limiter = createLimiter();
    expect(typeof limiter).toBe("object");
    expect(limiter).not.toBeNull();
    expect(typeof limiter.allow).toBe("function");
  });

  it("allow returns a strict boolean (never truthy/falsy surrogates)", () => {
    const limiter = createLimiter(1, 10);
    const first = limiter.allow("k", 0);
    const second = limiter.allow("k", 1);
    expect(first).toBe(true);
    expect(second).toBe(false);
    // Guard against returning e.g. counts or arrays that happen to be truthy.
    expect(typeof first).toBe("boolean");
    expect(typeof second).toBe("boolean");
  });
});

describe("createLimiter — basic allow/deny under the limit", () => {
  it("allows exactly `limit` calls at the same instant, then denies", () => {
    const limiter = createLimiter(3, 1000);
    expect(limiter.allow("k", 100)).toBe(true);
    expect(limiter.allow("k", 100)).toBe(true);
    expect(limiter.allow("k", 100)).toBe(true);
    // Fourth call at the same instant exceeds the limit.
    expect(limiter.allow("k", 100)).toBe(false);
    expect(limiter.allow("k", 100)).toBe(false);
  });

  it("allows a single call when limit is 1 and denies the next in-window call", () => {
    const limiter = createLimiter(1, 1000);
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 1)).toBe(false);
    expect(limiter.allow("k", 999)).toBe(false);
  });

  it("never allows any call when limit is 0", () => {
    const limiter = createLimiter(0, 1000);
    expect(limiter.allow("k", 0)).toBe(false);
    expect(limiter.allow("k", 500)).toBe(false);
    // Even far in the future, since nothing was ever recorded, still 0 < 0 is false.
    expect(limiter.allow("k", 10_000)).toBe(false);
  });
});

describe("createLimiter — defaults", () => {
  it("defaults to a limit of 5", () => {
    const limiter = createLimiter(); // limit = 5, windowMs = 60000
    for (let i = 0; i < 5; i++) {
      expect(limiter.allow("k", 0)).toBe(true);
    }
    expect(limiter.allow("k", 0)).toBe(false);
  });

  it("defaults to a window of 60000ms", () => {
    const limiter = createLimiter(); // windowMs = 60000
    // Fill the bucket at t = 0.
    for (let i = 0; i < 5; i++) expect(limiter.allow("k", 0)).toBe(true);
    // Just before the window elapses, still full -> denied.
    expect(limiter.allow("k", 59_999)).toBe(false);
    // The t=0 entry is still within window at t=60000-epsilon boundary check:
    // it expires only once now - windowMs >= 0, i.e. now >= 60000.
    expect(limiter.allow("k", 60_000)).toBe(true);
  });

  it("uses default window when only the limit is provided", () => {
    const limiter = createLimiter(2); // windowMs defaults to 60000
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 0)).toBe(false);
    // Still denied well within the default 60s window.
    expect(limiter.allow("k", 59_000)).toBe(false);
    // First entry expires exactly at 60000.
    expect(limiter.allow("k", 60_000)).toBe(true);
  });
});

describe("createLimiter — sliding-window expiry boundary", () => {
  it("treats a call exactly windowMs old as expired (t === now - windowMs)", () => {
    const limiter = createLimiter(1, 100);
    // Record at t = 0.
    expect(limiter.allow("k", 0)).toBe(true);
    // At now = 100: now - windowMs = 0, and 0 > 0 is false -> the entry has
    // expired and does not count, so this call is allowed.
    expect(limiter.allow("k", 100)).toBe(true);
  });

  it("keeps a call that is one ms short of expiring (t > now - windowMs)", () => {
    const limiter = createLimiter(1, 100);
    expect(limiter.allow("k", 0)).toBe(true);
    // At now = 99: now - windowMs = -1, and 0 > -1 is true -> still counts.
    expect(limiter.allow("k", 99)).toBe(false);
  });

  it("expires entries individually as the window slides", () => {
    const limiter = createLimiter(2, 100);
    // Two calls at t = 0 and t = 50 fill the bucket.
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 50)).toBe(true);
    expect(limiter.allow("k", 60)).toBe(false); // both still in window

    // At t = 100 the t=0 entry expires (0 > 0 is false), the t=50 entry
    // survives (50 > 0). One slot frees up.
    expect(limiter.allow("k", 100)).toBe(true);
    // Now t=50 and t=100 occupy the window -> full again.
    expect(limiter.allow("k", 100)).toBe(false);

    // At t = 150 the t=50 entry expires (50 > 50 is false); t=100 survives.
    expect(limiter.allow("k", 150)).toBe(true);
  });

  it("fully resets once the entire window has elapsed", () => {
    const limiter = createLimiter(3, 1000);
    for (let i = 0; i < 3; i++) expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 500)).toBe(false);
    // All three t=0 entries expire at t=1000.
    for (let i = 0; i < 3; i++) expect(limiter.allow("k", 1000)).toBe(true);
    expect(limiter.allow("k", 1000)).toBe(false);
  });
});

describe("createLimiter — denied calls record nothing", () => {
  it("a denied call does not consume a future slot", () => {
    const limiter = createLimiter(1, 10);
    expect(limiter.allow("k", 0)).toBe(true); // records t=0
    expect(limiter.allow("k", 5)).toBe(false); // denied, must NOT record t=5
    expect(limiter.allow("k", 5)).toBe(false); // still denied

    // t=0 expires at t=10. If the denied t=5 calls had been recorded, they
    // would still be within the window at t=11 (5 > 1) and deny this call.
    expect(limiter.allow("k", 11)).toBe(true);
  });

  it("repeated denials never accumulate to permanently block a key", () => {
    const limiter = createLimiter(2, 100);
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 0)).toBe(true);
    // Hammer with many denied calls throughout the window.
    for (let t = 1; t < 100; t++) {
      expect(limiter.allow("k", t)).toBe(false);
    }
    // Once the original two t=0 entries expire, the key is usable again and
    // none of the denied attempts left residue.
    expect(limiter.allow("k", 100)).toBe(true);
    expect(limiter.allow("k", 100)).toBe(true);
    expect(limiter.allow("k", 100)).toBe(false);
  });
});

describe("createLimiter — independent key buckets", () => {
  it("tracks each key separately", () => {
    const limiter = createLimiter(1, 1000);
    expect(limiter.allow("a", 0)).toBe(true);
    // b has its own bucket, unaffected by a.
    expect(limiter.allow("b", 0)).toBe(true);
    // a is now full.
    expect(limiter.allow("a", 0)).toBe(false);
    // b is now full too, independently.
    expect(limiter.allow("b", 0)).toBe(false);
  });

  it("exhausting one key does not affect another", () => {
    const limiter = createLimiter(2, 1000);
    expect(limiter.allow("a", 0)).toBe(true);
    expect(limiter.allow("a", 0)).toBe(true);
    expect(limiter.allow("a", 0)).toBe(false); // a exhausted

    // b still has full capacity.
    expect(limiter.allow("b", 0)).toBe(true);
    expect(limiter.allow("b", 0)).toBe(true);
    expect(limiter.allow("b", 0)).toBe(false);
  });

  it("supports many distinct keys concurrently", () => {
    const limiter = createLimiter(1, 1000);
    const keys = ["user:1", "user:2", "user:3", "", "0", "false"];
    for (const k of keys) expect(limiter.allow(k, 0)).toBe(true);
    for (const k of keys) expect(limiter.allow(k, 0)).toBe(false);
  });

  it("distinguishes keys that differ only by type-ish string form", () => {
    // Map keys use SameValueZero; distinct string keys are distinct buckets.
    const limiter = createLimiter(1, 1000);
    expect(limiter.allow("1", 0)).toBe(true);
    expect(limiter.allow("1", 0)).toBe(false);
    // A different key string is a fresh bucket.
    expect(limiter.allow("01", 0)).toBe(true);
  });
});

describe("createLimiter — `now` validation", () => {
  const invalidCases = [
    ["undefined", undefined],
    ["null", null],
    ["NaN", NaN],
    ["Infinity", Infinity],
    ["-Infinity", -Infinity],
    ["a string", "100"],
    ["a numeric-looking string", "0"],
    ["a boolean", true],
    ["an object", {}],
    ["an array", [100]],
    ["a bigint", 100n],
  ];

  for (const [label, value] of invalidCases) {
    it(`throws TypeError when now is ${label}`, () => {
      const limiter = createLimiter(5, 1000);
      expect(() => limiter.allow("k", value)).toThrow(TypeError);
    });
  }

  it("throws TypeError when now is omitted entirely", () => {
    const limiter = createLimiter(5, 1000);
    expect(() => limiter.allow("k")).toThrow(TypeError);
  });

  it("includes the offending value in the error message", () => {
    const limiter = createLimiter(5, 1000);
    expect(() => limiter.allow("k", NaN)).toThrow(/now must be a finite number/);
  });

  it("does not record anything when it throws on invalid now", () => {
    const limiter = createLimiter(1, 1000);
    expect(() => limiter.allow("k", NaN)).toThrow(TypeError);
    // The bucket must be untouched: a subsequent valid call still succeeds.
    expect(limiter.allow("k", 0)).toBe(true);
    expect(limiter.allow("k", 0)).toBe(false);
  });
});

describe("createLimiter — accepts all finite numbers as `now`", () => {
  it("accepts zero", () => {
    const limiter = createLimiter(1, 1000);
    expect(limiter.allow("k", 0)).toBe(true);
  });

  it("accepts negative timestamps and keeps the window arithmetic consistent", () => {
    const limiter = createLimiter(1, 100);
    expect(limiter.allow("k", -1000)).toBe(true);
    // now - windowMs = -1100; -1000 > -1100 -> still in window.
    expect(limiter.allow("k", -950)).toBe(false);
    // At now = -900: now - windowMs = -1000; -1000 > -1000 is false -> expired.
    expect(limiter.allow("k", -900)).toBe(true);
  });

  it("accepts fractional timestamps", () => {
    const limiter = createLimiter(1, 10);
    expect(limiter.allow("k", 0.5)).toBe(true);
    // 0.5 > 5.25 - 10 = -4.75 -> still in window.
    expect(limiter.allow("k", 5.25)).toBe(false);
    // At now = 10.5: now - windowMs = 0.5; 0.5 > 0.5 is false -> expired.
    expect(limiter.allow("k", 10.5)).toBe(true);
  });

  it("accepts non-monotonic (out-of-order) timestamps without crashing", () => {
    // The contract is defined purely in terms of `now`; it does not require
    // monotonicity. Going backwards simply re-evaluates the window at that now.
    const limiter = createLimiter(2, 100);
    expect(limiter.allow("k", 100)).toBe(true); // records 100
    expect(limiter.allow("k", 100)).toBe(true); // records 100
    expect(limiter.allow("k", 100)).toBe(false);
    // Jump backwards: at now = 50, entries at t=100 satisfy 100 > -50 -> count.
    expect(limiter.allow("k", 50)).toBe(false);
    // Far enough back that the window excludes the t=100 entries:
    // at now = 0, now - windowMs = -100; 100 > -100 is true, so still counted.
    expect(limiter.allow("k", 0)).toBe(false);
  });
});

describe("createLimiter — independent limiter instances", () => {
  it("does not share state between separate createLimiter() calls", () => {
    const a = createLimiter(1, 1000);
    const b = createLimiter(1, 1000);
    expect(a.allow("k", 0)).toBe(true);
    expect(a.allow("k", 0)).toBe(false);
    // b is a completely fresh limiter with the same key.
    expect(b.allow("k", 0)).toBe(true);
  });
});

describe("createLimiter — larger sliding-window scenario", () => {
  it("permits a steady stream at exactly the sustainable rate", () => {
    // limit 3 per 30ms window; one call every 10ms is sustainable forever.
    const limiter = createLimiter(3, 30);
    let t = 0;
    // Prime the window.
    expect(limiter.allow("k", t)).toBe(true); // t=0
    expect(limiter.allow("k", (t += 10))).toBe(true); // t=10
    expect(limiter.allow("k", (t += 10))).toBe(true); // t=20
    // Window now holds {0,10,20}; a 4th within window is denied.
    expect(limiter.allow("k", t)).toBe(false); // t=20, full
    // Advance to t=30: entry at 0 expires (0 > 0 false) -> allowed.
    expect(limiter.allow("k", (t += 10))).toBe(true); // t=30, holds {10,20,30}
    // Continue the cadence; each step drops exactly one stale entry.
    expect(limiter.allow("k", (t += 10))).toBe(true); // t=40, holds {20,30,40}
    expect(limiter.allow("k", (t += 10))).toBe(true); // t=50, holds {30,40,50}
  });

  it("denies a burst that exceeds the rate and recovers as the window slides", () => {
    const limiter = createLimiter(3, 100);
    // Burst of 5 at t=0: first 3 allowed, last 2 denied.
    const results = [0, 0, 0, 0, 0].map(() => limiter.allow("k", 0));
    expect(results).toEqual([true, true, true, false, false]);
    // Nothing recovers until the window fully clears at t=100.
    expect(limiter.allow("k", 99)).toBe(false);
    expect(limiter.allow("k", 100)).toBe(true);
  });
});

